import{_ as n,o as t,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F06: 存貨與債務穩定度審計","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F06_存貨與債務穩定度審計_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F06_存貨與債務穩定度審計_財務分析專家.md"}'),e={name:"32Ｑ題本＿重要/財務組/F06_存貨與債務穩定度審計_財務分析專家.md"};function l(a,o,s,c,d,g){return t(),i("div",null,[...o[0]||(o[0]=[r('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f06-存貨與債務穩定度審計" tabindex="-1">F06: 存貨與債務穩定度審計 <a class="header-anchor" href="#f06-存貨與債務穩定度審計" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F06</li><li><strong>題目：</strong> 存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「流動性風險分析 (Liquidity Risk Analysis)」與「資產負債管理」。能從存貨組成（原料/半成品/製成品）中讀取訂單去化動態，並精算償債倍數，是企業防禦力的終極評審。</li><li><strong>意圖：</strong> 執行「資產流動性與償債能力審計」。透過分析存貨水位與債務結構，判定公司是否面臨「庫存堆積導致跌價損失」或「流動性斷鏈」風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockBalanceSheet</code> 提取 <code>Inventories</code> (存貨)、<code>ShortTermBorrowings</code> (短期借款)、<code>LongTermBorrowings</code> (長期借款) 與 <code>QuickAssets</code> (速動資產)。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱 <code>財務報告附註 -&gt; 存貨組成</code> 與 <code>跌價損失準備</code>。</li><li><strong>【外部事實檢索：產業景氣循環】</strong>：搜尋該產業（如自行車、面板、半導體）目前是否處於「去庫存週期」。</li></ol></li><li><strong>邏輯：</strong> 執行「存貨/債務交叉覆蓋率測試」——若存貨週轉天數拉長且短期借款增加，判定為「庫存造成的現金流黑洞」；執行「跌價風險試算」。</li><li><strong>來源：</strong> <code>FinMind (資產/債務)</code>, <code>年度報告 (存貨附註)</code>, <code>財經新聞 (產業去庫存動態)</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py inventory_check [股號]</code> → 取得庫存週轉、DSO、DPO、現金循環</li><li><strong>取資產負債表</strong>：<code>python3 數據採集器.py balance_sheet [股號]</code> → 抓 <code>CashAndCashEquivalents</code>、<code>ShortTermBorrowings</code>、<code>LongTermBorrowings</code></li><li><strong>計算流動性</strong>：流動比率 = 流動資產/流動負債；速動比率 = (流動資產-存貨)/流動負債</li><li><strong>判讀</strong>：流動比率 &gt;200% = 優；100-200% = 正常；&lt;100% = 警戒</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具提取「存貨明細」和「借款附註」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【存貨組成分析】</strong>：智慧體<strong>必須</strong>列出最近三季的「存貨總額」。若「製成品」佔比異常升高而營收下滑，必須判定為「產品滯銷」。</li><li><strong>【償債壓力測試】</strong>：測算「(現金 + 速動資產) / 短期債務」。若比值 &lt; 1，且存貨週轉緩慢，必須發出「流動性斷鏈」之警訊。</li><li><strong>【跌價損失預警】</strong>：若存貨天數超過同業平均 30% 以上，必須強制要求智體評估其「跌價損失提列」是否足以覆蓋潛在價值衰減。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述約束】</strong>：絕對禁用「負債平穩」、「存貨充足」。必須量化為「存貨週轉率」與「流動比/速動比」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f06-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F06 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f06-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F06 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「資產流動性+債務壓力」結構（例：存貨 YOY 增加 X%，週轉天數拉長，雖 [短期債務] 有現金覆蓋，但 [庫存去化] 慢將導致未來跌價風險，評級為 [警訊]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：存貨週轉極快，現金完全覆蓋所有短債，且無長期償債壓力。</li><li><strong>A (良)</strong>：存貨水位與業績成長匹配，債務結構合理，利息支用比在安全水位。</li><li><strong>B (持平)</strong>：存貨積壓嚴重且債務倍數升高，現金流量難以支撐連續兩季以上的去庫存壓力，具備實質性的資產減值與違約風險。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確列出 FinMind 季度資產負債數據與計算得出的流動比率。</li></ul>',11)])])}const f=n(e,[["render",l]]);export{h as __pageData,f as default};
